const r = $('Verify query').first().json;
const num = (x) => Number(x);
const ok = num(r.stale_metrics) === 0 && num(r.orphans) === 0 && num(r.metrics_seen) === num(r.metrics_registered);
const emoji = ok ? '✅' : '⚠️';
const text = emoji + ' onchain-verify (daily)\n'
  + 'rows: ' + r.total_rows + ' · buckets: ' + r.buckets + '\n'
  + 'metrics seen: ' + r.metrics_seen + '/' + r.metrics_registered + '\n'
  + 'stale (>2h): ' + r.stale_metrics + ' · orphans: ' + r.orphans + '\n'
  + 'latest: ' + r.latest_ts_utc + ' UTC';
return [{ json: { ok, text } }];
